  2	using System.Net.Http.Headers;
  3	using System.Net.Http.Json;
  4	using System.Text.Json;
  5	using InventoryFlow.Application.Features.Authentication;
  6	using Microsoft.AspNetCore.Mvc.Testing;
  7	
  8	namespace InventoryFlow.IntegrationTests.Api;
  9	
 10	/// <summary>
 11	/// Verifies authentication against an isolated SQL Server instance.
 12	/// </summary>
 13	public sealed class AuthenticationEndpointsTests : IClassFixture<AuthenticatedApiFixture>
 14	{
 15	    private const string RefreshCookieName = "inventory_flow_refresh";
 16	    private static readonly JsonSerializerOptions JsonOptions = new(JsonSerializerDefaults.Web);
 17	    private readonly HttpClient _client;
 18	
 19	    /// <summary>
 20	    /// Initializes a new instance of the <see cref="AuthenticationEndpointsTests"/> class.
 21	    /// </summary>
 22	    /// <param name="fixture">The SQL Server-backed API fixture.</param>
 23	    public AuthenticationEndpointsTests(AuthenticatedApiFixture fixture)
 24	    {
 25	        _client = fixture.Factory.CreateClient(new WebApplicationFactoryClientOptions
 26	        {
 27	            HandleCookies = false,
 28	        });
 29	    }
 30	
 31	    /// <summary>
 32	    /// Registers a user and writes a secure browser-scoped refresh cookie.
 33	    /// </summary>
 34	    [Fact]
 35	    public async Task Register_WritesExpectedRefreshCookie()
 36	    {
 37	        // Act
 38	        using var response = await RegisterAsync();
 39	
 40	        // Assert
 41	        Assert.Equal(HttpStatusCode.OK, response.StatusCode);
 42	        var cookie = GetRefreshCookieHeader(response);
 43	        Assert.Contains("httponly", cookie, StringComparison.OrdinalIgnoreCase);
 44	        Assert.Contains("samesite=strict", cookie, StringComparison.OrdinalIgnoreCase);
 45	        Assert.Contains("path=/api/auth", cookie, StringComparison.OrdinalIgnoreCase);
 46	        Assert.Contains("max-age=", cookie, StringComparison.OrdinalIgnoreCase);
 47	    }
 48	
 49	    /// <summary>
 50	    /// Authorizes the current-user endpoint with the registration JWT.
 51	    /// </summary>
 52	    [Fact]
 53	    public async Task Me_WithIssuedAccessToken_ReturnsCurrentUser()
 54	    {
 55	        // Arrange
 56	        using var registration = await RegisterAsync();
 57	        var session = await ReadSessionAsync(registration);
 58	        using var request = new HttpRequestMessage(HttpMethod.Get, "/api/auth/me");
 59	        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", session.AccessToken);
 60	
 61	        // Act
 62	        using var response = await _client.SendAsync(request);
 63	
 64	        // Assert
 65	        Assert.Equal(HttpStatusCode.OK, response.StatusCode);
 66	        var user = await response.Content.ReadFromJsonAsync<AuthenticatedUser>(JsonOptions);
 67	        Assert.NotNull(user);
 68	        Assert.Equal(session.User.Email, user.Email);
 69	    }
 70	
 71	    /// <summary>
 72	    /// Rotates refresh tokens and invalidates an entire family after replay.
 73	    /// </summary>
 74	    [Fact]
 75	    public async Task Refresh_ReplayRevokesEntireTokenFamily()
 76	    {
 77	        // Arrange
 78	        using var registration = await RegisterAsync();
 79	        var originalCookie = GetRefreshCookieValue(registration);
 80	
 81	        // Act
 82	        using var rotated = await RefreshAsync(originalCookie);
 83	        var rotatedCookie = GetRefreshCookieValue(rotated);
 84	        using var replay = await RefreshAsync(originalCookie);
 85	        using var descendant = await RefreshAsync(rotatedCookie);
 86	
 87	        // Assert
 88	        Assert.Equal(HttpStatusCode.OK, rotated.StatusCode);
 89	        Assert.Equal(HttpStatusCode.Unauthorized, replay.StatusCode);
 90	        Assert.Equal(HttpStatusCode.Unauthorized, descendant.StatusCode);
 91	    }
 92	
 93	    /// <summary>
 94	    /// Revokes the browser's refresh-token family on logout.
 95	    /// </summary>
 96	    [Fact]
 97	    public async Task Logout_RevokesRefreshTokenFamily()
 98	    {
 99	        // Arrange
100	        using var registration = await RegisterAsync();
101	        var refreshCookie = GetRefreshCookieValue(registration);
102	
103	        // Act
104	        using var logout = await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/logout", refreshCookie);
105	        using var refresh = await RefreshAsync(refreshCookie);
106	
107	        // Assert
108	        Assert.Equal(HttpStatusCode.NoContent, logout.StatusCode);
109	        Assert.Equal(HttpStatusCode.Unauthorized, refresh.StatusCode);
110	    }
111	
112	    /// <summary>
113	    /// Permits only one concurrent refresh and treats the other request as replay.
114	    /// </summary>
115	    [Fact]
116	    public async Task Refresh_ConcurrentRequests_OnlyOneSucceedsAndRevokesFamily()
117	    {
118	        // Arrange
119	        using var registration = await RegisterAsync();
120	        var originalCookie = GetRefreshCookieValue(registration);
121	
122	        // Act
123	        var refreshes = await Task.WhenAll(
124	            RefreshAsync(originalCookie),
125	            RefreshAsync(originalCookie));
126	        using var first = refreshes[0];
127	        using var second = refreshes[1];
128	        var successfulRefresh = refreshes.Single(response => response.StatusCode == HttpStatusCode.OK);
129	        var replacementCookie = GetRefreshCookieValue(successfulRefresh);
130	        using var descendant = await RefreshAsync(replacementCookie);
131	
132	        // Assert
133	        Assert.Single(refreshes, response => response.StatusCode == HttpStatusCode.OK);
134	        Assert.Single(refreshes, response => response.StatusCode == HttpStatusCode.Unauthorized);
135	        Assert.Equal(HttpStatusCode.Unauthorized, descendant.StatusCode);
136	    }
137	
138	    private async Task<HttpResponseMessage> RegisterAsync()
139	    {
140	        var suffix = Guid.NewGuid().ToString("N");
141	        return await _client.PostAsJsonAsync(
142	            "/api/auth/register",
143	            new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
144	    }
145	
146	    private async Task<HttpResponseMessage> RefreshAsync(string refreshCookie) =>
147	        await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/refresh", refreshCookie);
148	
149	    private async Task<HttpResponseMessage> SendWithRefreshCookieAsync(
150	        HttpMethod method,
151	        string path,
152	        string refreshCookie)
153	    {
154	        using var request = new HttpRequestMessage(method, path);
155	        request.Headers.Add("Cookie", $"{RefreshCookieName}={refreshCookie}");
156	        return await _client.SendAsync(request);
157	    }
158	
159	    private static async Task<AuthenticationResponse> ReadSessionAsync(HttpResponseMessage response)
160	    {
161	        var session = await response.Content.ReadFromJsonAsync<AuthenticationResponse>(JsonOptions);
162	        return Assert.IsType<AuthenticationResponse>(session);
163	    }
164	
165	    private static string GetRefreshCookieHeader(HttpResponseMessage response) =>
166	        Assert.Single(response.Headers.GetValues("Set-Cookie"));
167	
168	    private static string GetRefreshCookieValue(HttpResponseMessage response)
169	    {
170	        var header = GetRefreshCookieHeader(response);
171	        var cookie = header.Split(';', 2)[0].Split('=', 2);
172	        Assert.Equal(RefreshCookieName, cookie[0]);
173	        return Uri.UnescapeDataString(cookie[1]);
174	    }
175	}
