138	    private async Task<HttpResponseMessage> RegisterAsync()
139	    {
140	        var suffix = Guid.NewGuid().ToString("N");
141	        return await _client.PostAsJsonAsync(
142	            "/api/auth/register",
143	            new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
144	    }
145	
146	    private async Task<HttpResponseMessage> RefreshAsync(string refreshCookie) =>
147	        await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/refresh", refreshCookie);
148	
149	    private async Task<HttpResponseMessage> SendWithRefreshCookieAsync(
150	        HttpMethod method,
151	        string path,
152	        string refreshCookie)
153	    {
154	        using var request = new HttpRequestMessage(method, path);
155	        request.Headers.Add("Cookie", $"{RefreshCookieName}={refreshCookie}");
156	        return await _client.SendAsync(request);
157	    }
158	
159	    private static async Task<AuthenticationResponse> ReadSessionAsync(HttpResponseMessage response)
160	    {
161	        var session = await response.Content.ReadFromJsonAsync<AuthenticationResponse>(JsonOptions);
162	        return Assert.IsType<AuthenticationResponse>(session);
163	    }
164	
165	    private static string GetRefreshCookieHeader(HttpResponseMessage response) =>
166	        Assert.Single(response.Headers.GetValues("Set-Cookie"));
167	
168	    private static string GetRefreshCookieValue(HttpResponseMessage response)
169	    {
170	        var header = GetRefreshCookieHeader(response);
171	        var cookie = header.Split(';', 2)[0].Split('=', 2);
172	        Assert.Equal(RefreshCookieName, cookie[0]);
173	        return Uri.UnescapeDataString(cookie[1]);
174	    }
