 23	    /// Adds SQL Server persistence and ASP.NET Core Identity services.
 24	    /// </summary>
 25	    /// <param name="services">The dependency-injection service collection.</param>
 26	    /// <param name="configuration">The application configuration.</param>
 27	    /// <returns>The supplied <paramref name="services"/> instance.</returns>
 28	    /// <exception cref="ArgumentException">Thrown when the database connection string is missing.</exception>
 29	    public static IServiceCollection AddInfrastructure(
 30	        this IServiceCollection services,
 31	        IConfiguration configuration)
 32	    {
 33	        ArgumentNullException.ThrowIfNull(services);
 34	        ArgumentNullException.ThrowIfNull(configuration);
 35	
 36	        var connectionString = configuration.GetConnectionString("InventoryFlowDatabase");
 37	        ArgumentException.ThrowIfNullOrWhiteSpace(
 38	            connectionString,
 39	            "ConnectionStrings:InventoryFlowDatabase");
 40	
 41	        services.AddOptions<JwtOptions>()
 42	            .Bind(configuration.GetSection(JwtOptions.SectionName))
 43	            .ValidateDataAnnotations()
 44	            .Validate(options => Encoding.UTF8.GetByteCount(options.SigningKey) >= 32, "Jwt signing key must be at least 32 bytes.")
 45	            .ValidateOnStart();
 46	        var jwt = configuration.GetSection(JwtOptions.SectionName).Get<JwtOptions>() ?? new JwtOptions();
 47	
 48	        services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
 49	            .AddJwtBearer(options =>
 50	            {
 51	                options.TokenValidationParameters = new TokenValidationParameters
 52	                {
 53	                    ValidateIssuer = true,
 54	                    ValidIssuer = jwt.Issuer,
 55	                    ValidateAudience = true,
 56	                    ValidAudience = jwt.Audience,
 57	                    ValidateIssuerSigningKey = true,
 58	                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwt.SigningKey)),
 59	                    ValidateLifetime = true,
 60	                    ClockSkew = TimeSpan.Zero,
 61	                    NameClaimType = "display_name"
 62	                };
 63	            });
 64	        services.AddSingleton(TimeProvider.System);
 65	        services.AddScoped<JwtAccessTokenIssuer>();
 66	        services.AddSingleton<RefreshTokenGenerator>();
 67	        services.AddScoped<IAuthenticationService, IdentityAuthenticationService>();
 68	
 69	        services.AddDbContext<ApplicationDbContext>(options => options.UseSqlServer(
 70	            connectionString,
 71	            sqlServerOptions => sqlServerOptions.EnableRetryOnFailure()));
 72	        services.AddDataProtection()
 73	            .SetApplicationName("InventoryFlow")
 74	            .PersistKeysToDbContext<ApplicationDbContext>();
 75	
 76	        services.AddIdentityCore<ApplicationUser>(options =>
 77	            {
 78	                options.User.RequireUniqueEmail = true;
 79	                options.Password.RequiredLength = 12;
 80	                options.Password.RequireDigit = true;
 81	                options.Password.RequireLowercase = true;
 82	                options.Password.RequireUppercase = true;
 83	                options.Password.RequireNonAlphanumeric = true;
 84	                options.Lockout.AllowedForNewUsers = true;
 85	                options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(15);
 86	                options.Lockout.MaxFailedAccessAttempts = 5;
 87	            })
 88	            .AddRoles<IdentityRole<Guid>>()
 89	            .AddEntityFrameworkStores<ApplicationDbContext>()
